using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Data.Entity;
using System.Linq;
using System.Text.RegularExpressions;
using System.Web;
using System.Web.Mvc;

namespace MyStore.Models
{
    public class Product
    {
        public int Id { get; set; }
        [Required] public string Name { get; set; }
        public string Description { get; set; }
        public virtual ICollection<Review> Reviews { get; set; }
    }

    public class Review
    {
        public int Id { get; set; }
        public int ProductId { get; set; }
        [Required] public string UserName { get; set; }
        [Required] public string Content { get; set; }
        public DateTime CreatedAt { get; set; }
        public virtual Product Product { get; set; }
    }
}

namespace MyStore.Data
{
    public class ApplicationDbContext : DbContext
    {
        public ApplicationDbContext() : base("DefaultConnection") { }
        public DbSet<Product> Products { get; set; }
        public DbSet<Review> Reviews { get; set; }
    }
}

namespace MyStore.Services
{
    public static class HtmlSanitizer
    {
        private static readonly Regex Stripper = new Regex(@"<(?!/?(b|i)\b)[^>]*>",
            RegexOptions.IgnoreCase | RegexOptions.Compiled);

        public static string Sanitize(string html)
        {
            if (string.IsNullOrWhiteSpace(html)) return string.Empty;
            var cleaned = Stripper.Replace(html, string.Empty);
            var encoded = HttpUtility.HtmlEncode(cleaned)
                .Replace("&lt;b&gt;", "<b>")
                .Replace("&lt;/b&gt;", "</b>")
                .Replace("&lt;i&gt;", "<i>")
                .Replace("&lt;/i&gt;", "</i>");
            return encoded;
        }
    }
}

namespace MyStore.ViewModels
{
    public class ReviewViewModel
    {
        public string UserName { get; set; }
        public string Content { get; set; }
        public DateTime CreatedAt { get; set; }
    }

    public class ProductDetailsViewModel
    {
        public Models.Product Product { get; set; }
        public IEnumerable<ReviewViewModel> Reviews { get; set; }
    }
}

namespace MyStore.Controllers
{
    public class ProductsController : Controller
    {
        private readonly Data.ApplicationDbContext _db = new Data.ApplicationDbContext();

        public ActionResult Details(int id)
        {
            var product = _db.Products.Find(id);
            if (product == null) return HttpNotFound();

            var reviews = _db.Reviews
                .Where(r => r.ProductId == id)
                .OrderByDescending(r => r.CreatedAt)
                .Select(r => new ViewModels.ReviewViewModel
                {
                    UserName = r.UserName,
                    Content = Services.HtmlSanitizer.Sanitize(r.Content),
                    CreatedAt = r.CreatedAt
                }).ToList();

            var vm = new ViewModels.ProductDetailsViewModel
            {
                Product = product,
                Reviews = reviews
            };
            return View(vm);
        }
    }
}

/* Views/Products/Details.cshtml */
@model MyStore.ViewModels.ProductDetailsViewModel
<h2>@Model.Product.Name</h2>
<p>@Model.Product.Description</p>
<h3>Reviews</h3>
@if (!Model.Reviews.Any())
{
    <p>No reviews yet.</p>
}
else
{
    foreach (var review in Model.Reviews)
    {
        <div class="review">
            <strong>@review.UserName</strong>
            <span>@review.CreatedAt:g</span>
            <p>@Html.Raw(review.Content)</p>
        </div>
    }
}